+    // --- Workspace changes ---
+
+    _onWorkspaceChanged() {
+        const activeWs = global.workspace_manager.get_active_workspace();
+        // Show/hide stamp containers based on whether their window is on
+        // the active workspace
+        for (const [metaWindow, state] of this._scaleManager._states) {
+            if (!state.container)
+                continue;
+            const onActiveWs = metaWindow.located_on_workspace(activeWs);
+            state.container.visible = onActiveWs;
+        }
+    }
